MERGE INTO TB_BOX_IVT_IVB101_M ivb101
USING DUAL ON (ivb101.FNCN_BSNS_PBAN_NO = #{fncnBsnsPbanNo} AND ivb101.FNCN_BSNS_RCIP_NO = #{fncnBsnsRcipNo})
WHEN MATCHED THEN
UPDATE SET
    FNCN_BSNS_ENLS_FILD_UQN = #{fncnBsnsEnlsFildUqn}
    ,FNCN_BSNS_PGRS_SCD = #{fncnBsnsPgrsScd}
    ,OPCM_NM = #{opcmNm}
    ,OPCM_RPPR_NM = #{opcmRpprNm}
    ,OPCM_INCR_YMD = #{opcmIncrYmd}
    ,OPCM_LICS_KCD = #{opcmLicsKcd}
    ,OPCM_BZN = #{opcmBzn}
    ,OPCM_RSPR_NM = #{opcmRsprNm}
    ,OPCM_CNPL_CON = #{opcmCnplCon}
    ,OPCM_EAD = #{opcmEad}
    ,JNT_OPCM_YN = #{jntOpcmYn}
    ,FUND_NM = #{fundNm}
    ,FNCN_BSNS_CPRT_DCD = #{fncnBsnsCprtDcd}
    ,IBK_FNCN_RQST_AMT = #{ibkFncnRqstAmt}
    ,FUND_ORGZ_SCDL_AMT = #{fundOrgzScdlAmt}
    ,FUND_ASCE_TRM = #{fundAsceTrm}
    ,FNMN_PMNT_MCD = #{fnmnPmntMcd}
    ,BASE_ENRT_CON = #{baseEnrtCon}
    ,MNRM_CON = #{mnrmCon}
    ,OTCM_RMNR_CON = #{otcmRmnrCon}
    
    ,RMRK_CON = #{rmrkCon}
    
    ,FILE_UNQ_NO = #{fileUnqNo}
    ,IIBS_LSMD_ID = #{iibsLsmdId}
    ,IIBS_LSMD_TS = CURRENT_TIMESTAMP
WHEN NOT MATCHED THEN
INSERT
(
    FNCN_BSNS_RCIP_NO
    ,FNCN_BSNS_PBAN_NO
    ,FNCN_BSNS_ENLS_FILD_UQN
    ,FNCN_BSNS_PGRS_SCD
    ,OPCM_NM
    ,OPCM_RPPR_NM
    ,OPCM_INCR_YMD
    ,OPCM_LICS_KCD
    ,OPCM_BZN
    ,OPCM_RSPR_NM
    ,OPCM_CNPL_CON
    ,OPCM_EAD
    ,JNT_OPCM_YN
    ,FUND_NM
    ,FNCN_BSNS_CPRT_DCD
    ,IBK_FNCN_RQST_AMT
    ,FUND_ORGZ_SCDL_AMT
    ,FUND_ASCE_TRM
    ,FNMN_PMNT_MCD
    ,BASE_ENRT_CON
    ,MNRM_CON
    ,OTCM_RMNR_CON
    
    ,RMRK_CON
    
    ,FILE_UNQ_NO
    ,DEL_YN
    ,IIBS_FRRG_TS
    ,IIBS_FRRG_ID
) VALUES
(
    #{fncnBsnsRcipNo}
    ,#{fncnBsnsPbanNo}
    ,#{fncnBsnsEnlsFildUqn}
    ,#{fncnBsnsPgrsScd}
    ,#{opcmNm}
    ,#{opcmRpprNm}
    ,#{opcmIncrYmd}
    ,#{opcmLicsKcd}
    ,#{opcmBzn}
    ,#{opcmRsprNm}
    ,#{opcmCnplCon}
    ,#{opcmEad}
    ,#{jntOpcmYn}
    ,#{fundNm}
    ,#{fncnBsnsCprtDcd}
    ,#{ibkFncnRqstAmt}
    ,#{fundOrgzScdlAmt}
    ,#{fundAsceTrm}
    ,#{fnmnPmntMcd}
    ,#{baseEnrtCon}
    ,#{mnrmCon}
    ,#{otcmRmnrCon}
    
    ,#{rmrkCon}
    
    ,#{fileUnqNo}
    ,'N'
    ,CURRENT_TIMESTAMP
    ,#{iibsFrrgId}
 )

