mapper.select:
SELECT ivb001.FNCN_BSNS_PBAN_NO ,ivb001.FNCN_BSNS_PBAN_TTL_NM ,ivb001.PBAN_YMD ,ivb001.FNCN_BSNS_PBAN_DCD ,ivb101.FNCN_BSNS_RCIP_NO ,ivb101.FNCN_BSNS_ENLS_FILD_UQN ,ivb101.FNCN_BSNS_PGRS_SCD ,ivb101.DEL_YN ,TO_TIMESTAMP(ivb101.IIBS_FRRG_TS) as IIBS_FRRG_TS ,ivb101.IIBS_FRRG_ID FROM TB_BOX_IVT_IVB101_M ivb101 LEFT JOIN TB_BOX_IVT_IVB001_M ivb001 ON ivb101.FNCN_BSNS_PBAN_NO = ivb001.FNCN_BSNS_PBAN_NO WHERE ivb101.IIBS_FRRG_ID = #{searchIibsFrrgId}
AND ivb101.FNCN_BSNS_PGRS_SCD = #{searchFncnBsnsPgrsScd}
AND ivb001.FNCN_BSNS_PBAN_TTL_NM LIKE '%' || #{searchName} || '%'
AND ivb001.FNCN_BSNS_PBAN_TTL_NM LIKE '%' || #{searchName} || '%'
ORDER BY ivb101.IIBS_FRRG_TS DESC

mapper.update:
UPDATE
    TB_BOX_IVT_IVB101_M
SET
    FNCN_BSNS_PGRS_SCD = #{fncnBsnsPgrsScd}
WHERE
    FNCN_BSNS_RCIP_NO = #{fncnBsnsRcipNo}
